define("local_consentmanager/preferences",["core/ajax","core/notification","core/pending","core/str"],function(Ajax,Notification,Pending,Str){"use strict";

function init(){
    document.querySelectorAll(".consentmanager-withdraw").forEach(b=>b.addEventListener("click",handleWithdraw));
    document.querySelectorAll(".consentmanager-give").forEach(b=>b.addEventListener("click",handleGive));
}

async function handleWithdraw(e){
    const btn=e.currentTarget,catid=parseInt(btn.dataset.catid,10);
    const label=await Str.get_string("btn_withdraw_confirm","local_consentmanager");
    if(!window.confirm(label))return;
    const pending=new Pending("local_consentmanager/preferences/withdraw");
    btn.disabled=true;
    try{
        const calls=Ajax.call([{methodname:"local_consentmanager_withdraw_consent",args:{catid}}]);
        const result=await calls[0];
        if(result.success){window.location.reload();}else{Notification.alert("",result.message);}
    }catch(err){Notification.exception(err);}finally{btn.disabled=false;pending.resolve();}
}

async function handleGive(e){
    const btn=e.currentTarget,catid=parseInt(btn.dataset.catid,10);
    const pending=new Pending("local_consentmanager/preferences/give");
    btn.disabled=true;
    try{
        const calls=Ajax.call([{methodname:"local_consentmanager_set_consent",args:{catids:[catid],acceptall:false}}]);
        const result=await calls[0];
        if(result.success){window.location.reload();}else{Notification.alert("",result.message);}
    }catch(err){Notification.exception(err);}finally{btn.disabled=false;pending.resolve();}
}

return{init};
});
